class User:
    def __init__(self, role):
        self.role = role

def calculate_discount(role):
    if role.lower() == 'enterprise':
        return 0.3
    elif role.lower() == 'premium':
        return 0.15
    else:
        return 0

def calculate_cart_total(cart_items):
    return sum(item['price'] * item['quantity'] for item in cart_items)

def process_payment(user, cart_items, payment_details):
    cart_total = calculate_cart_total(cart_items)
    discount = calculate_discount(user.role)
    amount_to_pay = cart_total - (cart_total * discount)

    if amount_to_pay > payment_details['amount']:
        return "Insufficient balance"
    else:
        payment_details['amount'] -= amount_to_pay
        return "Payment successful"